            case 3: return IdentityState.PinViolation;
            case 4: return IdentityState.VerificationViolation;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeIdentityState.Read()", value));
        }
    }

    public override int AllocationSize(IdentityState value) {
        return 4;
    }

    public override void Write(IdentityState value, BigEndianStream stream) {
        switch (value) {
            case IdentityState.Verified: stream.WriteInt(1); break;
            case IdentityState.Pinned: stream.WriteInt(2); break;
            case IdentityState.PinViolation: stream.WriteInt(3); break;
            case IdentityState.VerificationViolation: stream.WriteInt(4); break;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeIdentityState.Write()", value));
        }
    }
}







