/// <summary>
/// Error type for the decoding of the [`QrCodeData`].
/// </summary>
public class LoginQrCodeDecodeException: UniffiException {
    LoginQrCodeDecodeException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    /// <summary>
    /// The QR code data is no long enough, it's missing some fields.
    /// </summary>
    public class NotEnoughData: LoginQrCodeDecodeException {
        public NotEnoughData(string message): base(message) {}
    }
    
    /// <summary>
    /// One of the URLs in the QR code data is not a valid UTF-8 encoded string.
    /// </summary>
    public class NotUtf8: LoginQrCodeDecodeException {
        public NotUtf8(string message): base(message) {}
    }
    
    /// <summary>
    /// One of the URLs in the QR code data could not be parsed.
    /// </summary>
    public class UrlParse: LoginQrCodeDecodeException {
        public UrlParse(string message): base(message) {}
    }
    
    /// <summary>
    /// The QR code data contains an invalid intent, we expect the login
    /// intent or the reciprocate intent.
    /// </summary>
    public class InvalidIntent: LoginQrCodeDecodeException {
        public InvalidIntent(string message): base(message) {}
    }
    
    /// <summary>
    /// The QR code data contains an unsupported type.
    /// </summary>
    public class InvalidType: LoginQrCodeDecodeException {
        public InvalidType(string message): base(message) {}
    }
    
    /// <summary>
    /// The base64 encoded variant of the QR code data is not a valid base64
    /// string.
    /// </summary>
    public class Base64: LoginQrCodeDecodeException {
        public Base64(string message): base(message) {}
    }
    
    /// <summary>
    /// The QR code data doesn't contain the expected `MATRIX` prefix.
    /// </summary>
    public class InvalidPrefix: LoginQrCodeDecodeException {
        public InvalidPrefix(string message): base(message) {}
    }
    
}

class FfiConverterTypeLoginQrCodeDecodeError : FfiConverterRustBuffer<LoginQrCodeDecodeException>, CallStatusErrorHandler<LoginQrCodeDecodeException> {
    public static FfiConverterTypeLoginQrCodeDecodeError INSTANCE = new FfiConverterTypeLoginQrCodeDecodeError();

    public override LoginQrCodeDecodeException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new LoginQrCodeDecodeException.NotEnoughData(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new LoginQrCodeDecodeException.NotUtf8(FfiConverterString.INSTANCE.Read(stream));
            case 3: return new LoginQrCodeDecodeException.UrlParse(FfiConverterString.INSTANCE.Read(stream));
            case 4: return new LoginQrCodeDecodeException.InvalidIntent(FfiConverterString.INSTANCE.Read(stream));
            case 5: return new LoginQrCodeDecodeException.InvalidType(FfiConverterString.INSTANCE.Read(stream));
            case 6: return new LoginQrCodeDecodeException.Base64(FfiConverterString.INSTANCE.Read(stream));
            case 7: return new LoginQrCodeDecodeException.InvalidPrefix(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeLoginQrCodeDecodeError.Read()", value));
        }
    }

    public override int AllocationSize(LoginQrCodeDecodeException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(LoginQrCodeDecodeException value, BigEndianStream stream) {
        switch (value) {
            case LoginQrCodeDecodeException.NotEnoughData:
                stream.WriteInt(1);
                break;
            case LoginQrCodeDecodeException.NotUtf8:
                stream.WriteInt(2);
                break;
            case LoginQrCodeDecodeException.UrlParse:
                stream.WriteInt(3);
                break;
            case LoginQrCodeDecodeException.InvalidIntent:
                stream.WriteInt(4);
                break;
            case LoginQrCodeDecodeException.InvalidType:
                stream.WriteInt(5);
                break;
            case LoginQrCodeDecodeException.Base64:
                stream.WriteInt(6);
                break;
            case LoginQrCodeDecodeException.InvalidPrefix:
                stream.WriteInt(7);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeLoginQrCodeDecodeError.Write()", value));
        }
    }
}





